const raw = $input.first().json.content.parts[0].text;                        

 let cleaned = raw                                                             
   .replace(/```json\n?/g, '')
   .replace(/```\n?/g, '')                                                     
   .trim();                                                                    

 const arrayMatch = cleaned.match(/\[[\s\S]*\]/);
 if (!arrayMatch) throw new Error('No JSON array found');
 cleaned = arrayMatch[0];

 const weeks = JSON.parse(cleaned);

 return weeks.map(week => {
   const prompts = Array.isArray(week.discussion_prompts) ?
 week.discussion_prompts : [];
   const activities = Array.isArray(week.activity_ideas) ? week.activity_ideas
 : [];
   return { json: {
     course_id: $('Webhook - Weekly Feedback').item.json.body.course_id,
     week_number: week.week_number,
     teaching_notes: week.teaching_notes || '',
     discussion_prompts: prompts,
     activity_ideas: activities
   } };
 });
